async function bindleftCommonSearchdropdown(vm, moduleName, filtername) {
   if(filtername=='Status'){
        var params = `statusType=${moduleName}&&hasglobal=${false}`;
        await DataService.GetStatusList(params).then(async (response) => {
            if (response.data.length > 0) { 
                const targetField = vm.leftSearchFields.find(field => field.fieldName === 'Status');
                if (targetField) {
                    targetField.listOptions = response.data.map(element => ({ name: element.STATUS, value: element.STATUS_ID }));
                }              
            }
        });
    }
    else if(filtername=='QuotationType'){   
        await DataService.GetQuotationTypes().then(async (response) => {            
            if (response.data.data.length > 0) { 
                const targetField = vm.leftSearchFields.find(field => field.fieldName === 'Quotation Type');
                if (targetField) {
                    targetField.listOptions = response.data.data.map(element => ({ name: element.quotE_TYPE_NAME, value: element.quotE_TYPE_ID }));
                }              
            }
        });
    }
}


export default { buttons, leftsearchSchema,listActions,bindleftCommonSearchdropdown};
