<template>
    <section>
        <loader :is-visible="isLoading"></loader>
        <tg-list ref="tgList" :listType="['List']" :IsShowAction="true" :showCheckBox="true" ModuleName="PROJECT"
            SubModuleCode="Project_Detail" IdentityColumn="quotationId" :HeaderText="$t('Quotes')"
            :ListData="QuotationData" :HeaderData="Headers" :widgets="widgets" :HeaderButtons="listheaderbuttons"
            :TotalRecords="TotalRecords" :SearchFields="leftSearchFields" :RenderRowActionMethod="renderActions"
            :ListDataCallBackFunction="FetchData" :SortExp="SortExp" :SortBy="SortBy" :LegendArray="LegendArray"
            :NorecordfoundText="$t('NoRecordfound')" v-on:LeftsearchButtonClick="leftCommonSearch"
            v-on:PagerButtonClick="pagerMethod" v-on:HeaderButtonClick="commonHeaderButtonClick"
            v-on:ActionButtonClick="actionButtonClick" v-on:SortdataButtonClick="sortdata">
            <template v-slot:slotdata="{ data }">
                <template v-if="data.column.COLUMN_NAME == 'quotationNumber'">
                    <div v-if="UserRole == 'CL'">
                        {{ data.row.quotationNumber }}
                    </div>
                    <div v-else>
                        <div v-if="data.row.status == 'QUOTE_SENT' || 'QUOTE_REJ' || 'QUOTE_APPR'">
                            <a class="text-primary">{{ data.row.quotationNumber }}</a>
                        </div>
                        <div v-else>
                            <a class="text-primary">{{ data.row.quotationNumber }}</a>
                        </div>
                    </div>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'quotationTitle'">
                    {{ $t(TruncateStr(data.row.quotationTitle, 25)) }}
                </template>
                <template v-if="data.column.COLUMN_NAME == 'quotationType'">
                    {{ $t(TruncateStr(data.row.quotationTypeName, 25)) }}
                </template>
                <template v-if="data.column.COLUMN_NAME == 'owner'">
                    {{ $t(TruncateStr(data.row.owner, 25)) }}
                </template>
                <template v-if="data.column.COLUMN_NAME == 'status'">
                    <span v-if="data.row.status =='ACT'">
                        <a class="inactive-disabled"><span class="bg-success text-white btn d-inline-block w-80 text-center text-truncate">Active</span></a>
                    </span>
                    <span v-if="data.row.status =='CLBDFT'">
                       <a class="inactive-disabled"><span class="sts-ticket_draft text-white btn d-inline-block w-80 text-center text-truncate">Draft</span></a>
                    </span>
                    <span v-if="data.row.status =='QUOTE_SENT'">
                       <a class="inactive-disabled"><span class="bg-primary text-white btn d-inline-block w-80 text-center text-truncate">Sent</span></a>
                    </span>
                    <span v-if="data.row.status =='QUOTE_REJ'">
                       <a class="inactive-disabled"><span class="bg-danger text-white btn d-inline-block w-80 text-center text-truncate">Rejected</span></a>
                    </span>
                    <span v-if="data.row.status =='QUOTE_APPR'">
                       <a class="inactive-disabled"><span class="bg-info text-white btn d-inline-block w-80 text-center text-truncate">Approved</span></a>
                    </span>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'startDate'">
                    {{ data.row.startDate != null ? $d(data.row.startDate,"MM/DD/YYYY") : '--' }}
                </template>
                <template v-if="data.column.COLUMN_NAME == 'endDate'">
                    {{ data.row.startDate != null ? $d(data.row.endDate,"MM/DD/YYYY") : '--' }}
                </template>
                <template v-if="data.column.COLUMN_NAME == 'netPayableAmount'">
                    <div>
                        <span>
                            {{ $n(data.row.netPayableAmount, "currency", $getLocaleByCurrency(data.row.iso_Code)) }}
                        </span>
                    </div>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'crmName'">
                    <div v-if="UserRole != 'CL'">
                        <div>
                            {{
                                (data.column.COLUMN_NAME == 'quotationType' &&
                                    (data.row.quotationType == 2 || data.row.quotationType == 4 || data.row.quotationType == 5))
                                    ? (data.row.crmName != null ? data.row.crmName : '--')
                                    : '--'
                            }}
                        </div>

                    </div>
                </template>
                <template v-if="data.column.COLUMN_NAME == 'clientName'">
                    {{ data.row.clientName != null ? data.row.clientName : '--' }}
                </template>

                <template v-if="data.column.COLUMN_NAME == 'Regnarate'">
                    <div class="single-action">
                        <a v-if="(data.row.status == 'ACT' || data.row.status == 'QUOTE_REJ') && data.row.quotationTypeName != 'Draft'"
                            title="" class="cursorpointer ancRegenerateQuotation" :qid="data.row.qid"  @click="ShowRegenerateQuote(data)"
                            data-toggle-tooltip="tooltip" data-original-title="Regenerate">
                            <em class="fa fa-refresh text-info action-icon"></em>
                        </a>
                        <em v-else class="fa fa-refresh text-info action-icon disabled"></em>
                    </div>
                </template>
                 <template v-if="data.column.COLUMN_NAME == 'Edit'">
                    <div class="single-action">
                        <a v-if="(data.row.status == 'ACT')"
                         title="" id="ancEditQuotation" :qid="data.row.qid"  data-toggle-tooltip="tooltip" data-original-title="Edit Quotes">
                                                        <em class="fa fa-pencil text-success action-icon enable"></em>
                                                    </a>
                        <em v-else class="fa fa-pencil text-success action-icon d-none"></em>
                    </div>
                </template>
            </template>
        </tg-list>
        <div class="my-popups" v-if="IsShowTemplate">
            <loader :is-visible="isLoading"></loader>
            <div class="modal d-block">
                <div class="modal-dialog modal-dialog-centered">
                    <div class="modal-content">
                        <div class="modal-header theme-primary partition-full  d-flex">
                            <h4 class="modal-title"> {{  $t('BillTemplate') }}</h4>
                            <button type="button" class="close" v-on:click="IsShowTemplate=false">
                                <em class="fa fa-times" aria-hidden="true"></em>
                            </button>
                        </div>
                        <div class="modal-body">
                          <div v-html="TemplateContent"></div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
        <AddQuote v-if="IsQuoteModel" @callbackfunction="CloseModel" @AddNewQuote="AddNewQuote"></AddQuote>
        <RegenerateQuote v-if="IsRegenerateQuote" :RegenerateQuoteData="RegenerateQuoteData"></RegenerateQuote>
    </section>
</template>
<script>
import Schema from './QuotationListSchema'
import DataService from '../../../services/DataService'
import AddQuote from './AddNewQuote.vue'
import RegenerateQuote from '../../../components/Modal/RegenerateQuote.vue';
export default {
    components: {AddQuote, RegenerateQuote},
    data() {
        return {
            IsQuoteModel:false,
            isLoading: false,
            IsShowTemplate:false,
            IsRegenerateQuote: false,
            RegenerateQuoteData: [],
            QuotationData: [],
            listheaderbuttons: Schema.buttons,
            leftSearchFields: Schema.leftsearchSchema,
            listActions: Schema.listActions,
            UserRole: '',
            Headers: [],
            widgets: [],
            searchCondition: '',
            TotalRecords: 0,
            title: '',
            qno: '',
            dateFrom: '',
            dateTo: '',
            statuses: '',
            quotationCodes: '',
            PageNumber: 1,
            PageSize: 10,
            SortBy: '',
            SortExp: '',
            LegendArray: [{
                class: 'legends_high colorboxsquare',
                text: (this.$t('DraftMode'))
            },
            {
                class: 'legend-ovrdue colorboxsquare',
                text: (this.$t('Expired'))
            }
            ],
            Headers: [
                {
                    "COLUMN_NAME": "quotationNumber",
                    "DATA_TYPE": "string",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": this.$t('Quote Number'),
                    "DISPLAY_ORDER": 1,
                    settings: {
                        isInSlot: true,
                    }
                },
                {
                    "COLUMN_NAME": "quotationTitle",
                    "DATA_TYPE": "string",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": this.$t('Title'),
                    "DISPLAY_ORDER": 2,
                    settings: {
                        isInSlot: true,
                    }
                },
                {
                    "COLUMN_NAME": "quotationType",
                    "DATA_TYPE": "string",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": this.$t('Type'),
                    "DISPLAY_ORDER": 3,
                    settings: {
                        isInSlot: true,
                    }
                },
                {
                    "COLUMN_NAME": "owner",
                    "DATA_TYPE": "string",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": this.$t('Owner Name'),
                    "DISPLAY_ORDER": 4,
                    settings: {
                        isInSlot: true,
                    }
                },
                {
                    "COLUMN_NAME": "status",
                    "DATA_TYPE": "string",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": this.$t('STATUS_ID'),
                    "DISPLAY_ORDER": 5,
                    settings: {
                        isInSlot: true,
                    }
                },
                {
                    "COLUMN_NAME": "startDate",
                    "DATA_TYPE": "string",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": this.$t('Issue Date'),
                    "DISPLAY_ORDER": 6,
                    // settings: {
                    //      isInSlot: true,
                    //  }

                },
                {
                    "COLUMN_NAME": "endDate",
                    "DATA_TYPE": "string",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": this.$t('Due Date'),
                    "DISPLAY_ORDER": 7,
                    //  settings: {
                    //      isInSlot: true,
                    //  }
                },
                {
                    "COLUMN_NAME": "netPayableAmount",
                    "DATA_TYPE": "string",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": this.$t('Amount'),
                    "DISPLAY_ORDER": 3,
                    settings: {
                        isInSlot: true,
                    }
                },
                {
                    "COLUMN_NAME": "clientName",
                    "DATA_TYPE": "string",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": this.$t('Client'),
                    "DISPLAY_ORDER": 8,
                    settings: {
                        isInSlot: true,
                    }
                },
                {
                    "COLUMN_NAME": "crmName",
                    "DATA_TYPE": "string",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": this.$t('CRM Name'),
                    "DISPLAY_ORDER": 9,
                    settings: {
                        isInSlot: true,
                    }
                },
                {
                    "COLUMN_NAME": "projectName",
                    "DATA_TYPE": "string",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": this.$t('projectname'),
                    "DISPLAY_ORDER": 10
                },
                {
                    "COLUMN_NAME": "projectRequestTitle",
                    "DATA_TYPE": "string",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": this.$t('Project Request'),
                    "DISPLAY_ORDER": 11
                },
                {
                    "COLUMN_NAME": "Regnarate",
                    "DATA_TYPE": "string",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": this.$t('Regnarate'),
                    "DISPLAY_ORDER": 12,
                     settings: {
                        isInSlot: true,
                    }

                },
                {
                    "COLUMN_NAME": "Edit",
                    "DATA_TYPE": "string",
                    "SORTABLE": true,
                    "VISIBLE": true,
                    "DISPLAY_NAME": this.$t('Edit'),
                    "DISPLAY_ORDER": 13,
                     settings: {
                        isInSlot: true,
                    }

                }
            ],
            TodoStatusData: [],
            GetQuotationTypeCode: [
                { name: 'Project Request', value: 1 },
                { name: 'Lead', value: 2 },
                { name: 'Client', value: 3 },
                { name: 'Prospect', value: 4 },
                { name: 'Opportunity', value: 5 },
                { name: 'Project', value: 6 },
            ],
             CurrencyCode:'PKR',
             TemplateContent:'',
        }
    },
    created: function () {
        var ths = this;
        ths.UserRole = ths.GetUserInfo.UserType;
        ths.CurrencyCode = ths.GetUserInfo.Currency.replace(/[()]/g, '');
        Schema.bindleftCommonSearchdropdown(ths, "Quotation", "Status"); 
        Schema.bindleftCommonSearchdropdown(ths, "Quotation", "QuotationType");   
        ths.FetchData();
        if (ths.UserRole == 'CL'){
            ths.listheaderbuttons[1].isvisible = true;
            ths.listheaderbuttons[2].isvisible = true;
        } 
    },
    methods: {
        ShowRegenerateQuote(itm){
            var vm = this;
            vm.RegenerateQuoteData = itm.row;
            vm.IsRegenerateQuote = true;
        }, 
        FetchData() {
            var vm = this;
            var url = `pageSize=${vm.PageSize}&pageNum=${vm.PageNumber}&title=${vm.title}&qno=${vm.qno}&dateFrom=${vm.dateFrom}&dateTo=${vm.dateTo}&sortBy=&sortExp=&statuses=${vm.statuses}&quotationCodes=${vm.quotationCodes}`
            DataService.QuotationsList(url).then((response) => {
                debugger
                if (response.data.data.length > 0) {
                    vm.QuotationData = response.data.data;
                    vm.QuotationData.forEach((item) => {                        
                        if (vm.UserRole == 'CL' && item.status == 'QUOTE_SENT') {
                            item.isCheckBoxDisabled = true;
                        } else {
                            if (item.status == 'ACT' || item.status == 'CLBDFT') {
                                item.isCheckBoxDisabled = true;
                            }
                        }
                        item.quotationTypeName = vm.GetQuotationTypeCode.filter(x => x.value == item.quotationType)[0].name;
                        item.TodoStatusData = [];
                        let objToDoStatus = null;
                        if (item.status == 'ACT') {
                            objToDoStatus = { Name: "Active", Color: "#28a745" };
                            item.TodoStatusData.push(objToDoStatus);
                        }
                        if (item.status == 'CLBDFT') {
                            objToDoStatus = { Name: "Draft", Color: "#6c757d" };
                            item.TodoStatusData.push(objToDoStatus);
                        }
                        if (item.status == 'QUOTE_SENT') {
                            objToDoStatus = { Name: "Sent", Color: "#007bff" };
                            item.TodoStatusData.push(objToDoStatus);
                        }
                        if (item.status == 'QUOTE_REJ') {
                            objToDoStatus = { Name: "Rejected", Color: "#dc3545" };
                            item.TodoStatusData.push(objToDoStatus);
                        }
                        if (item.status == 'QUOTE_APPR') {
                            objToDoStatus = { Name: "Approved", Color: "#17a2b8" };
                            item.TodoStatusData.push(objToDoStatus);
                        }
                    });
                    vm.TotalRecords = response.data.data[0].totalRecord;
                    vm.TotalPages = Math.ceil(vm.TotalRecords / vm.PageSize);
                    vm.CurrentPage = vm.PageNumber;                    
                }
            });
        },
        renderActions: function (row) {
            var self = this;
            let rtnActionArray = [];
            self.listActions.forEach(actionItem => {
                let action = { ...actionItem };
                switch (action.title) {
                    case 'Reject Quotation':
                        action.isDisabled = true;
                        action.isVisible = self.UserRole == 'CL' ? true : false;
                        break;
                    case 'Approve Quotation':
                        action.isDisabled = true;
                        action.isVisible = self.UserRole == 'CL' ? true : false;
                        break;
                    case 'View Quotation':
                        action.isVisible = true;
                        break;
                    case 'Send Quotation':                         
                            if((row.status == "ACT" || row.status == "QUOTE_REJ") && row.quotationNumber != "Draft Mode"){
                                action.isVisible = false;
                                action.isDisabled = false;
                            }
                            if(row.quotationNumber == "Draft Mode"){
                                action.isVisible = true;
                                action.isDisabled = true;
                            }                        
                        break;
                    case 'Edit Quotation':
                        action.isVisible = true;
                        break;
                    default: {
                        action.isVisible = true;
                    }
                }
                rtnActionArray.push(action);
            });
            return rtnActionArray;
        },
        leftCommonSearch: function (value) {
            this.PageNumber = value.PageNumber;
            this.isPaged = 1;
            if (typeof value.searchCondition != 'undefined') {
                if (value.searchConditionJson != '') {
                     const filedName = value.searchConditionJson.split('=')[0];                     
                     if(filedName=='qno')
                     {
                         this.qno = value.searchConditionJson.split('=')[1];
                     }
                     else if(filedName=='title')
                     {
                         this.title = value.searchConditionJson.split('=')[1];
                     }
                     else if(filedName=='dateFrom')
                     {
                        this.dateFrom = value.searchConditionJson.split('=')[1];
                     }
                     else if(filedName=='dateTo')
                     {
                         this.dateTo = value.searchConditionJson.split('=')[1];
                     }
                      else if(filedName=='Statuses')
                     {
                         this.statuses = value.searchConditionJson.split('=')[1];
                     }
                } 
                else {
                    this.searchCondition = "";
                    this.qno='';
                    this.title='';
                    this.dateFrom='';
                    this.dateTo='';
                    this.statuses='';
                }
            }
            else {
                this.searchCondition = "";
                this.qno='';
                this.title='';
                this.dateFrom='';
                this.dateTo='';
                this.statuses='';
            }
            this.FetchData();
        },
        pagerMethod: function (value) {
            this.PageSize = value.PageSize;
            this.PageNumber = value.PageNumber;
            this.FetchData();
        },
        actionButtonClick: function (callbackfunction, item) {
            switch (callbackfunction) {
                case "RejectQuotation":
                    this.RejectQuotation(item.quotationId);
                    break;
                case "ApproveQuotation":
                    this.ApproveQuotation(item.quotationId);
                    break;
                case "ViewQuotation":
                    this.ViewQuotation(item);
                    break;
                case "SendQuotation":
                    this.SendQuotation(item);
                    break;
                case "EditQuotation":
                    this.EditQuotation(item);
                    break;
            }
        },
        ViewQuotation(item)
        {
            debugger
             var vm=this;
            vm.$router.push({name :"DisplayQuotation", params: {  QuotationId: item.quotationId || 0,Code: 1 } })

            // vm.IsShowTemplate=true;
            // vm.isLoading = true;
            // var url=`template_id=${item.templateId}&Quote_id=${item.quotationId}`;
            // DataService.GetTemplateById(url).then((response)=>{
            //      if(response.data !='')
            //      {
            //         vm.TemplateContent=vm.ReplaceTemplateVariables(response.data.templateData,response.data.quote.result[0]);
            //      }
            //      vm.isLoading = false;
            // }); 
        },
        ReplaceTemplateVariables(template, item) {
            if (!template || !item) return template;
            const u = item.USER_DETAIL?.[0] || {};
            const q = item.QUOTATION_DETAIL || {};
            var totalAmount = 0;
            var subtotal = 0;
            var advanceRecived = 0;
            var adjustment = 0
            q.forEach((element) => {
                totalAmount += element.TOTAL_LINE_PRICE;
                subtotal += element.TOTAL_LINE_PRICE;
                advanceRecived += element.ADVANCE_RECIEVED;
            });
            const replacements = {
                '@BillAddress@': u.COMPANY_LOCATION || '--',
                '@BillCity@': u.COMPANY_CITY || '--',
                '@BillState@': u.COMPANY_STATE || '--',
                '@BillCountry@': u.COMPANY_COUNTRY || '--',
                '@BillZip@': u.COMPANY_PINCODE || '--',
                '@ClientBillAddress@': u.USER_ADDRESS_1 || '--',
                '@ClientBillCity@': u.USER_CITY || '--',
                '@ClientBillState@': u.USER_STATE || '--',
                '@ClientBillCountry@': u.COUNTRY_NAME || '--',
                '@ClientBillZip@': u.ZIP_CODE || '--',
                '@BillPhone@': u.COMPANY_PHONE || '--',
                '@ClientBillPhone@': item.clientPhone || '--',
                '@Email@': u.COMPANY_EMAIL || '',
                '@ClientProjectName@': u.PROJECT_NAME || '',
                '@CompanyName@': u.COMPANY_NAME || '',
                '@ClientNameOnBill@': [u.FIRST_NAME, u.LAST_NAME].filter(Boolean).join(' ') || '',
                '@Logo@': `<img src="${u.company_logo || ''}" alt="Company Logo" height="50">`,
                '@BillNumber@': q[0].QUOTATION_BILL_ITEM_ID || '',
                '@BillIssueDate@': q[0].START_DATE ? this.$d(new Date(q[0].START_DATE)) : '',
                '@BillDueDate@': q[0].END_DATE ? this.$d(new Date(q[0].END_DATE)) : '',
                '@BillDateComments@': '--',
                '@SubTotal@': totalAmount || '0.00',
                '@BillAdjustments@':  '',
                '@BillTotalNoAdv@': totalAmount || '0.00',
                '@BillAdvanceAmount@': '0.00',
                '@BillNetTotal@': totalAmount || '0.00',
                '@Currency@': q[0].ISO_CODE || '',
                '@BillDescription@': q[0].DESCRIPTION || '--',
                 '@Items@': this.GenerateItemsTable(q || [])
            };
            for (const [key, value] of Object.entries(replacements)) {
                const regex = new RegExp(key, 'g');
                template = template.replace(regex, value);
            }

            return template;
        },
GenerateItemsTable(items) {
    debugger
    if (!items.length) return '<p>No items found.</p>';
    let html = `
        <table width="100%" border="1" cellspacing="0" cellpadding="5" style="border-collapse: collapse; font-size: 0.9em;">
            <thead>
                <tr style="background-color:#f2f2f2;">
                    <th align="left">#</th>
                    <th align="left">Product Name</th>
                    <th align="left">Qty</th>
                    <th align="left">Rate</th>
                    <th align="left">Amount</th>
                </tr>
            </thead>
            <tbody>
    `;

    items.forEach((item, index) => {
        html += `
            <tr >
                <td>${index + 1}</td>
                <td>${item.ITEM || ''}</td>
                <td align="left">${item.QUANTITY || 0}</td>
                <td align="left">${item.BILLING || 0}</td>
                <td align="left">${item.BILLED_AMT || 0}</td>
            </tr>
        `;
    });

    html += '</tbody></table></br>';
    return html;
},
        sortdata: function (s) {
            var SortDir = "sort tb_headerSortDown";
            this.SortBy = s;
            if (s === this.SortBy) {
                if (this.SortExp == "") {
                    this.SortExp = "ASC";
                    SortDir = "sort tb_headerSortDown";
                }
                else if (this.SortExp == "ASC") {
                    this.SortExp = "DESC";
                    SortDir = "sort tb_headerSortUp";
                }
                else {
                    this.SortExp = "ASC";
                    SortDir = "sort tb_headerSortDown";
                }
            }
            this.FetchData();
            $("#" + s + '  span:first-child').attr("class", SortDir);
        },
        commonHeaderButtonClick: function (event) {
            switch (event.callbackfunction) {
                case "AddQuote":
                    this.AddQuote();
                    break;     
                case "ApproveQuote":
                    this.ApproveQuotation();
                    break;
                case "RejectQuote":
                    this.RejectQuotation();
                    break; 
                case "commonDeleteData":
                    this.commonDeleteData();
                    break;             
            }
        }, 
        AddQuote()
        {
          this.IsQuoteModel=true;
        },
        CloseModel()
        {
             this.IsQuoteModel=false; 
        },
        AddNewQuote(Type,Name,CheckType){
            var ths=this;
            ths.CloseModel();
            var url=`id=${Type}&primaryKey=${Name}`
            DataService.GetQuotationUrl(url).then(function (response) { 
                if(response.status > 0){
                    if(CheckType=='Project'){
                        ths.Quotation(response.data.projecT_ID,response.data.projecT_NAME,Type,0,0,ths.CurrencyCode);
                    }
                    else if(CheckType=='Client'){ 
                        ths.Quotation(0, null, Type, Name, 0, response.data || response.data || ''); 
                    }
                    else if(CheckType=='Project Request'){
                        ths.Quotation(response.data.projectRequestId, response.data.projectTitle, Type, response.data.createdBy, 'ProjectRequest', ths.CurrencyCode);
                    }
                }
            })
        },
        Quotation(id, name, type, clientId, requestFromPop, CurrencyCode) {
            this.$router.push({ 
                name: 'Quotation', 
                params: { 
                    id: id || 0, 
                    code: type || '',
                    clientId: clientId || 0, 
                    title: name || 'N/A', 
                    requestFromPop: requestFromPop || 0,
                    currency: CurrencyCode || '', 
                    reform: 'Quote' 
                } 
            });
        },
        async ApproveQuotation (itm) {
            var vm = this;
            var jsonobj = {
                Ids: itm,
                StatusCode: 'QUOTE_SENT'
            };
            var params = JSON.stringify(jsonobj);
            await DataService.ApproveRejectQuotation(params).then((response) => {
                if (response.data.status == 'Success') {
                    vm.ShowAlert(vm.$t("UpdatedSuccess", [vm.$t("Quotation")]), "success", true, vm.$t("Alert"));
                    vm.FetchData();
                }
                else {
                    vm.ShowAlert(vm.$t("AddedError", [vm.$t("Quotation")]), "failure", true, vm.$t("Alert"));
                }
            });
        },
        async RejectQuotation (itm) {
            var vm = this;
            var jsonobj = {
                Ids: itm,
                StatusCode: 'QUOTE_SENT'
            };
            var params = JSON.stringify(jsonobj);
            await DataService.ApproveRejectQuotation(params).then((response) => {
                if (response.data.status == 'Success') {
                    vm.ShowAlert(vm.$t("UpdatedSuccess", [vm.$t("Quotation")]), "success", true, vm.$t("Alert"));
                    vm.FetchData();
                }
                else {
                    vm.ShowAlert(vm.$t("AddedError", [vm.$t("Quotation")]), "failure", true, vm.$t("Alert"));
                }
            });
        },
        commonDeleteData: function (id) {   
            var vm = this;
            var val = "";
            vm.isLoading = true;
            if (id == null) {
                $('.chkItems:checkbox:checked').not("[id^='chkAll_0']").each(function () {
                    if (val.length > 0)
                        val += ',';
                    val += $(this).val();
                });
            }
            else {
                val = id;
            }
            if (val != null) {
                vm.confirmR(vm.$t("ConfirmDelete"), true, (vm.$t("Delete") + "  " + vm.$t("Group")), function () { 
                    var url=`ids=${val}&tablename=Talygen_crm_quotation&key=quotation_id`;                 
                    DataService.DeleteItems(url).then(function (response) {                        
                        if (response.status == 200) {
                            vm.ShowAlert(vm.$t('DeletedSuccess', [vm.$t('Quotation')]), "success", true, vm.$t("Alert"));
                            vm.FetchData();
                        }
                        else {
                            vm.ShowAlert(vm.$t('DeletedError', [vm.$t('Quotation')]), "Success", true, vm.$t("Alert"));
                        }
                    });
                });
            }
            else {
                vm.ShowAlert(vm.$t("Selectanyrecordtodelete"));
            }
            vm.isLoading = false;
        }
    }
}
</script>