<template lang="en">
<div class="my-popups">
    <loader :is-visible="isLoading"></loader>
    <div class="modal d-block">
        <div class="modal-dialog modal-dialog-centered">
            <div class="modal-content">
                <div class="modal-header theme-primary partition-full  d-flex">
                    <h4 class="modal-title">{{ $t('Regenerate Quote') }}</h4>
                    <span class="user-guide">
                        <a class="ancuserguide text-white" data-toggle="collapse" href="#collapseReplyUG" role="button" aria-expanded="false" aria-controls="collapseExample"> <em class="fa fa-files-o pr-2"></em>{{ $t('GuideForUser') }}</a>
                        <div id="collapseReplyUG" class="divancuserguide collapse overflow-auto">
                            <div id="scrollbarreplyuserguideMangeView" class="custom-scrollbar-js">
                                <div class="con" v-html="$t('UgHiringAddDepartment')"></div>
                            </div>
                        </div>
                    </span>
                    <button type="button" class="close" v-on:click="Close">
                        <em class="fa fa-times" aria-hidden="true"></em>
                    </button>
                </div>
                <div class="modal-body">
                    <dynamic-form lang="en" :buttons="buttons" :schema="FormSchema" :mandatorytext='MandatoryString'></dynamic-form>
                </div>
            </div>
        </div>
    </div>
</div>
</template>

<script>
import DataService from '../../services/DataService';
export default {
    props: {
        RegenerateQuoteData : {
            type: String,
            required: true
        }
    },
    data() {
        return {
            isLoading: false,
            QuotationId: 0,
            QuoteData: [],
            BillingData: [],
            AdjustmentData: [],
            MandatoryString: 'Fields marked with an asterisk (*) are mandatory.',
            FormSchema: [{
                layoutType: "double",
                Data: [{
                        astype: "DateField",
                        label: this.$t('Issue Date (DD/MM/YYYY)'),
                        name: "IssueDate",
                        value: (new Date()),
                        placeholder: "",
                        config: {
                            options: [],
                            format: "M/D/YYYY",
                            minDate: new Date(),
                        },
                        validationRules: {
                            "required": true
                        },
                        visibility: true,
                        disabled: false
                    },
                    {
                        astype: "DateField",
                        label: this.$t('Due Date (DD/MM/YYYY)'),
                        name: "DueDate",
                        value: (new Date()),
                        placeholder: "",
                        config: {
                            options: [],
                            format: "M/D/YYYY",
                            minDate: new Date(),
                        },
                        validationRules: {
                            "required": true
                        },
                        visibility: true,
                        disabled: false
                    }
                ]
            }],
            buttons: [{
                    type: "submit",
                    class: "btn btn-warning",
                    text: "<i class='fa fa-save pr-2'></i>Save As Draft",
                    isVisible: true,
                    value: "DraftMode",
                    onClick: this.saveForm
                },
                {
                    type: "button",
                    class: "btn btn-success",
                    text: "<i class='fa fa-angle-double-right pr-2'></i>Generate",
                    onClick: this.saveForm
                }
            ]
        }
    },
    created: function () {
        var vm = this;
        vm.QuoteId = vm.RegenerateQuoteData.quotationId;
        if (vm.QuoteId > 0){
            vm.GetRegenerateQuotation();
        }        
    },
    methods: {
        GetRegenerateQuotation: function () {
            var vm = this;
            vm.isLoading = true;
            var params = `QuotationId=${vm.QuoteId}`;           
            DataService.GetRegenerateQuotation(params).then((response) => {
                if (response.data && response.data.status == 'Success') {
                    vm.QuoteData = response.data.result.DATA[0];
                    vm.AdjustmentData = response.data.result.TAX;
                    vm.BillingData = response.data.result.BILLING[0];
                } 
                vm.isLoading = false;
            })
        },
        saveForm: function (btnType) {
            debugger
            var vm = this;
            vm.isLoading = true; 
            var jsonobj = {
                QuotationId: vm.QuotationId,
                QuotationTitle: vm.QuoteData.QUOTATIONTITLE,
                TemplateId: vm.QuoteData.TEMPLATEID,
                QuotationNumber: btnType.value == "DraftMode"? 'Draft Mode' :vm.QuoteData.QUOTATIONNUMBER,
                QuotationType: vm.QuoteData.QUOTATIONTYPE,
                QuotationTypeID: vm.QuoteData.QUOTATIONTYPEID,
                QuotationOwner: vm.QuoteData.QUOTATIONOWNER,
                Owner: vm.QuoteData.QUOTATIONOWNER,
                StartDate: vm.$options.filters.formatDateYMD(vm.FormSchema[0].Data[0].value),
                EndDate: vm.$options.filters.formatDateYMD(vm.FormSchema[0].Data[1].value),
                Description: vm.QuoteData.DESCRIPTION,
                QuotationTypeCode: vm.QuoteData.QUOTATIONTYPECODE,
                ClientName: null,
                ClientId: vm.QuoteData.CLIENTID,
                ProjectRequestId: vm.QuoteData.PROJECTREQUESTID,
                ProjectRequestTitle: null,
                LeadId: vm.QuoteData.LEADID,
                CrmName: null,
                LeadOwnerId: null,
                ShippingAddress: vm.QuoteData.SHIPPINGADDRESS,
                TotalLinePrice: vm.QuoteData.TOTALLINEPRICE,
                AmountAfterDiscount: vm.QuoteData.AMOUNTAFTERDISCOUNT,
                FlatDiscount: vm.QuoteData.FLATDISCOUNT,
                AdvanceRecieved: vm.QuoteData.ADVANCERECEIVED,
                DiscountType: true,
                StatusId: vm.QuoteData.QUOTATIONNUMBER == 'Draft Mode' ? 1074 : 1001,
                Status: vm.QuoteData.STATUS,
                ProjectId: vm.QuoteData.PROJECTID,
                ProjectName: null,
                NetPayableAmount: vm.QuoteData.NETPAYABLEAMOUNT,
                TotalProfitAmount: vm.QuoteData.TOTALPROFITAMOUNT,
                BillingItems: vm.BillingData,
                Adjustments: vm.AdjustmentData
            };
            var params = JSON.stringify(jsonobj);
            DataService.SaveQuote(params).then((response) => {
                if (response.data.status == "Success") {
                    vm.ShowAlert(vm.$t('AddedSuccess', [vm.$t('Regenerate Quote')]), "success", true, vm.$t("Alert"));
                    vm.$parent.FetchData();
                    vm.Close();
                } else {
                    vm.ShowAlert(vm.$t('AddedError', [vm.$t('Regenerate Quote')]), "failure", true, vm.$t("Alert"));
                    vm.Close();
                }
                vm.isLoading = true; 
            });                           
        }, 
        Close: function () {
            this.$parent.IsRegenerateQuote = false;
        }
    }
}
</script>
