<template>
    <section>
        <div class="my-popups">
            <loader :is-visible="isLoading"></loader>
            <div class="modal d-block">
                <div class="modal-dialog modal-dialog-centered">
                    <div class="modal-content">
                        <div class="modal-header theme-primary partition-full  d-flex">
                            <h4 class="modal-title"> {{  $t('Add') + ' ' + $t('Quote')  }}</h4>
                            <button type="button" class="close" v-on:click="CloseQuote">
                                <em class="fa fa-times" aria-hidden="true"></em>
                            </button>
                        </div>
                        <div class="modal-body">
                            <dynamic-form lang="en" :buttons="buttons" :schema="FormSchema"  ref="QuoteForm"
                                :mandatorytext='MandatoryString' v-on:OnSubmit="OnSubmit"></dynamic-form>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    </section>
</template>

<script>
import DataService from '../../../services/DataService';
export default {
    data() {
        return {
            Quotemodelvisible: false,
            isLoading:false,             
            MandatoryString: 'Fields marked with an asterisk (*) are mandatory.',
            FormSchema: [{  layoutType: "double",
                Data: [ 
                {
                    astype: "SelectField",
                    label: this.$t('Quotation Type'),
                    name: "QuotationType",
                    value: "",
                    
                    config: {
                        options: [],
                        onChange: this.BindClientField
                    },
                    placeholder: this.$t('Select Quotation Type'),
                    validationRules: { "required": true, max: 100 },
                },
                {
                    astype: "SelectField",
                    label: this.$t('Select Name'),
                    name: "SelectName",
                    value: "",
                     visibility:false,
                    config: {
                        options: []
                    },
                    placeholder: this.$t('Select Select Name'),
                    validationRules: { "required": true, max: 100 },
                },

            ]
            }],
            buttons: [
                {
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-save pr-2'></i>Save",
                    isVisible: true
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Cancel",
                    onClick: this.CloseQuote,
                },
            ],
            CheckType:[]
        }
    }, 
    created: function(){
        var ths = this;
        ths.GetQuotationTypes();
    },
    methods: {
        GetQuotationTypes(){
            var ths=this;
            ths.FormSchema[0].Data[0].config.options=[];
            DataService.GetQuotationTypes().then(async (response) => {    
            if (response.data.data.length > 0) {  
                if (response.data.data.length > 0) {
                    ths.FormSchema[0].Data[0].config.options = response.data.data.map(element => ({ name: element.quotE_TYPE_NAME, value: element.quotE_TYPE_ID }));
                }   
                ths.$refs.QuoteForm.UpdateKeyValue();               
            }
        });
        },
        BindClientField(itm){
            var vm=this;
            vm.FormSchema[0].Data[1].visibility=true;  
            var code= vm.FormSchema[0].Data[0].value;
            var url=`code=${code}`;
            vm.CheckType=vm.FormSchema[0].Data[0].config.options.filter(element=>element.value==code);
            vm.FormSchema[0].Data[1].config.options=[];  
             DataService.GetNamesOrTitles(url).then(response=>{
                if(response.data.length>0){
                    vm.FormSchema[0].Data[1].config.options=response.data.map(element=>({name:element.TEXT,value:element.VALUE}))
                }
                vm.$refs.QuoteForm.UpdateKeyValue();                      
             })
        },
        CloseQuote() {
            this.$emit('callbackfunction');
        },
        OnSubmit:function(){
            this.$emit('AddNewQuote',this.FormSchema[0].Data[0].value,this.FormSchema[0].Data[1].value,this.CheckType[0].name);
        }
    }
}
</script>